import { Router } from "express";
import { AuthController } from "./auth.controller";
import { UserRole } from "../../../generated/prisma/enums";
import authCheck from "../../middleware/authCheck";
import { multerUpload } from "../../../config/multerConfig";
const router = Router();
router.post("/sign-up/email", multerUpload.single("image"), AuthController.registerUser);
router.post("/sign-in/email", AuthController.loginUser);
router.get("/me", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.CONSUMER, UserRole.OWNER), AuthController.getMe);
router.get("/refresh-token", AuthController.getNewToken);
router.post("/change-password", authCheck(UserRole.ADMIN, UserRole.CONSUMER, UserRole.SUPER_ADMIN, UserRole.OWNER), AuthController.changePassword);
router.post("/logout", authCheck(UserRole.ADMIN, UserRole.CONSUMER, UserRole.SUPER_ADMIN, UserRole.OWNER), AuthController.logoutUser);
router.post("/verify-email", AuthController.verifyEmail);
router.post("/resend-otp", AuthController.resendOtp);
router.post("/forget-password", AuthController.forgetPassword);
router.post("/reset-password", AuthController.resetPassword);
router.get("/login/google", AuthController.googleSignIn);
router.get("/google/success", AuthController.googleSignInSuccess);
router.get("/google/failure", AuthController.googleSignInFailure);
export const authRoute = router;
